document.addEventListener("DOMContentLoaded",function(){function e(){const e=document.querySelectorAll("#post-list li");if(!e.length){console.log("No list items found.");return}let t=0;e.forEach(e=>{const n=e.querySelector("span");if(n){const e=n.textContent.length;e>t&&(t=e)}}),e.forEach(e=>{const n=e.querySelector("span");if(n){const e=n.textContent.length,s=t-e+3;n.innerHTML+=".".repeat(s)+" "}})}e()})